// Determine current state and whether we should notify.
// Simplified: health is based ONLY on HTTP status code (2xx = healthy).
// Body parsing was removed because it caused false negatives when response
// format was unexpected (e.g. Cloudflare 404 HTML page).

const resp = $input.first().json;
const statusCode = resp.statusCode ?? 0;

// Healthy = any 2xx HTTP status code
const isHealthy = statusCode >= 200 && statusCode < 300;
const currentState = isHealthy ? 'UP' : 'DOWN';

// Read last known state from static data (persisted across workflow runs)
const staticData = $getWorkflowStaticData('global');
const lastState = staticData.lastState || 'UP'; // default UP on first run

// Decide what to notify about:
// - State transition UP -> DOWN: send DOWN alert
// - State transition DOWN -> UP: send RECOVERY alert
// - Same state: stay silent
let notifyType = null;
if (lastState === 'UP' && currentState === 'DOWN') {
  notifyType = 'DOWN';
} else if (lastState === 'DOWN' && currentState === 'UP') {
  notifyType = 'RECOVERY';
}

// Persist new state for next run
staticData.lastState = currentState;
staticData.lastChecked = new Date().toISOString();

return [{
  json: {
    statusCode,
    isHealthy,
    currentState,
    lastState,
    notifyType,
    timestamp: staticData.lastChecked
  }
}];
